(() => { const copyText = async (text) => { const value = String(text || '').trim(); if (!value) return false; try { await navigator.clipboard.writeText(value); return true; } catch (_) { try { const ta = document.createElement('textarea'); ta.value = value; ta.style.position = 'fixed'; ta.style.opacity = '0'; document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove(); return true; } catch (__) { return false; } } }; const toast = (message) => { let el = document.querySelector('.pro-toast'); if (!el) { el = document.createElement('div'); el.className = 'pro-toast'; el.setAttribute('role', 'status'); document.body.appendChild(el); } el.textContent = message; el.classList.add('is-show'); clearTimeout(el._timer); el._timer = setTimeout(() => el.classList.remove('is-show'), 1500); }; document.addEventListener('click', async (event) => { const copyBtn = event.target.closest('[data-provider-code-copy]'); if (copyBtn) { event.preventDefault(); const code = copyBtn.getAttribute('data-provider-code-copy'); const ok = await copyText(code); toast(ok ? `가입코드 ${code} 복사 완료` : `가입코드 ${code} 확인`); return; } const visit = event.target.closest('[data-provider-visit]'); if (visit) { event.preventDefault(); const code = visit.getAttribute('data-provider-code'); if (code) await copyText(code); toast(code ? `가입코드 ${code} 복사 후 이동합니다` : '사이트로 이동합니다'); const url = visit.getAttribute('href'); setTimeout(() => { if (url) window.open(url, '_blank', 'noopener,noreferrer'); }, 120); } });
})();